import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/macos-settings.e7FrcLCc.js";import{t as o}from"./chunks/updating-fabric.1C0PZ95m.js";const s=JSON.parse(`{"title":"在 macOS 上更新 Fabric","description":"在 macOS 上更新 Fabric 的逐步指南。","frontmatter":{"title":"在 macOS 上更新 Fabric","description":"在 macOS 上更新 Fabric 的逐步指南。","authors":["IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"zh_cn/players/updating-fabric/macos.md","filePath":"translated/zh_cn/players/updating-fabric/macos.md","lastUpdated":1770561656000}`);var c={name:`zh_cn/players/updating-fabric/macos.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 macOS 上更新 Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “在 macOS 上更新 Fabric”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. 下载 Fabric 安装程序 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. 下载 Fabric 安装程序”">​</a></h2><p>从 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 网站</a>下载 Fabric 安装程序的 <code>.jar</code> 版本，单击 <code>Download installer (Universal/.JAR)</code>。</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. 运行 Fabric 安装程序 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. 运行 Fabric 安装程序”">​</a></h2><p>请先关闭 Minecraft 和 Minecraft 启动器，然后再运行安装程序。</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>你可能会收到一条警告，提示 Apple 无法验证 <code>.jar</code> 文件。 要绕过此警告，请打开系统设置 &gt; 隐私和安全，然后单击 <code>仍然打开</code>。 如果出现提示，请确认并输入你的管理员密码。</p><p><img src="/assets/players/installing-fabric/macos-settings.png" alt="macOS 系统设置" loading="lazy"></p></div><p>打开安装程序后，你应该会看到类似这样的屏幕：</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="高亮显示“安装”的 Fabric 安装程序" loading="lazy"></p><p>请确保新游戏版本和加载器版本正确，然后单击 <code>安装</code> 以更新 Fabric。</p><div class="warning custom-block"><p class="custom-block-title">重要</p><p>当你运行安装器时，确保你取消勾选了“创建配置文件”！</p></div><h2 id="3-update-launcher-profile" tabindex="-1">3. 在 Minecraft Launcher 中更新配置文件 <a class="header-anchor" href="#3-update-launcher-profile" aria-label="Permalink to “3. 在 Minecraft Launcher 中更新配置文件”">​</a></h2><p>安装完成后，打开 Minecraft Launcher。 然后前往“安装”选项卡。 找到你的 Fabric 配置文件并打开其编辑界面：</p><p><img src="/assets/players/updating-fabric.png" alt="在 Minecraft 启动器中更新 Fabric Loader 版本" loading="lazy"></p><p>将该版本替换为刚才安装的 Fabric Loader 版本并点击 <code>保存</code>。</p><h2 id="4-you-re-done" tabindex="-1">4. 大功告成！ <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. 大功告成！”">​</a></h2><p>完成这些步骤后，就可以回到 <code>Play</code> 选项卡，从左下角的下拉菜单中选择 Fabric 配置文件，然后按下启动按钮！</p><p>如果在遵循本指南时遇到任何问题，可以在 <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p>`,17)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};